const notas = [4, 5, 3, 5, 2];

// filter: solo las que aprueban (>= 3)
const aprobadas = notas.filter(n => n >= 3);
console.log(aprobadas);   // [4, 5, 3, 5]

// find: la primera nota perfecta
const perfecta = notas.find(n => n === 5);
console.log(perfecta);    // 5

// map: subir todas medio punto
const subidas = notas.map(n => n + 0.5);
console.log(subidas);     // [4.5, 5.5, 3.5, 5.5, 2.5]

